#include<bits/stdc++.h>
using namespace std;
struct node
{
    int x,y;
    bool operator<(const node&b)const
    {
        return x<b.x;
    }
}a[100010];
deque<int> q1,q2;
int main()
{
    int n,d;
    scanf("%d%d",&n,&d);
    int r=0;
    for(int i=1;i<=n;i++)
    {
        scanf("%d%d",&a[i].x,&a[i].y);
    }
    sort(a+1,a+1+n);
    int ans=INT_MAX;
    for(int l=0;l<=n;l++)
    {
        while(!q1.empty()&&q1.front()<l)
        {
            q1.pop_front();
        }
        while(!q2.empty()&&q2.front()<l)
        {
            q2.pop_front();
        }
        while((q1.empty()||q2.empty()||a[q1.front()].y-a[q2.front()].y<d)&&r<n)
        {
            r++;
            while(!q1.empty()&&a[q1.back()].y<a[r].y)
            {
                q1.pop_back();
            }
            q1.push_back(r);
            while(!q2.empty()&&a[q2.back()].y>a[r].y)
            {
                q2.pop_back();
            }
            q2.push_back(r);
        }
        if(r<n)
        {
            ans=min(ans,a[r].x-a[l].x);
        }
    }
    if(ans==INT_MAX)
    {
        printf("-1");
        return 0;
    }
    printf("%d",ans);
    return 0;
}
